// c is from ClockDomain A; x, y, z are from ClockDomain B
// The control dependency on c means z implicitly depends on A
logic c;
logic x, y, z;
assign z = c ? x : y;

// Domain A drives select; Domain B drives data and output
// Tool should detect that output z inherits a dependency on Domain A
logic [0:0] sel_domA;
logic [7:0] data_domB_0, data_domB_1;
logic [7:0] out_domB;
assign out_domB = sel_domA ? data_domB_1 : data_domB_0;
